async def main():
    game_id = 3

    async with uow:
        for team_name, team_image in teams_data.items():
            session = boto3.session.Session(
                aws_access_key_id=ConfigEnv.S3_ACCESS,
                aws_secret_access_key=ConfigEnv.S3_SECRET,
            )
            s3_client = session.client(
                service_name="s3",
                endpoint_url=ConfigEnv.S3_ENDPOINT_URL
            )

            temp = NamedTemporaryFile(delete=False)
            contents = requests.get(team_image).content
            with temp as f:
                f.write(contents)

            saved_key = str(uuid.uuid4())
            s3_client.upload_file(temp.name, ConfigEnv.S3_BUCKET, saved_key)

            obj_id = await uow.upload_repo.add_one({
                'name': 'logo.png',
                'owner_id': None,
                'content_category': UploadContentCategory.UNKNOWN.value,
                'object_key': saved_key,
                'bucket': ConfigEnv.S3_BUCKET,
            })
            team_id = await uow.team.add_one({
                "name": team_name,
                "access_type": TeamAccessTypes.PUBLIC,
                "image_id": obj_id,
                "game_id": game_id,
                "creator_id": None,
            })

            time.sleep(1)

        await uow.commit()

if __name__ == '__main__':
    asyncio.run(main())
